const doc = new Document({
  styles: { /* build_styles_config output */ },
  numbering: { config: [ /* build_numbering_config output */ ] },
  footnotes: { /* if plan has footnotes */ },
  sections: plan.sections.map(sectionSpec => ({
    properties: {
      page: { /* plan.page_setup */ },
      ...(sectionSpec.skip_header_footer ? {} : {
        header: /* build_headers_footers header */,
        footer: /* build_headers_footers footer */,
      }),
    },
    children: [
      /* section code from SectionCode.code — inserted as raw JS expressions */
    ],
  })),
});
const buffer = await Packer.toBuffer(doc);
writeFileSync('output.docx', buffer);
